CREATE TABLE cart (
  item_id   INT PRIMARY KEY,
  product   VARCHAR(60),
  quantity  INT,
  price     DECIMAL(8,2)
);

INSERT INTO cart VALUES
  (1, 'Laptop',    1, 999.99),
  (2, 'Mouse',     2,  19.99),
  (3, 'Keyboard',  1,  59.99);

SELECT * FROM cart;

BEGIN;
  -- Add headphones
  INSERT INTO cart VALUES (4, 'Headphones', 1, 79.99);
  SAVEPOINT after_headphones;

  -- Add monitor
  INSERT INTO cart VALUES (5, 'Monitor', 1, 299.99);
  SAVEPOINT after_monitor;

  -- Add webcam (but user changes mind)
  INSERT INTO cart VALUES (6, 'Webcam', 1, 49.99);
  -- User removes webcam but keeps headphones and monitor
  ROLLBACK TO SAVEPOINT after_monitor;

  -- Confirm: webcam gone, headphones and monitor still there
  SELECT * FROM cart ORDER BY item_id;
COMMIT;

-- Final state
SELECT * FROM cart ORDER BY item_id;

CREATE TABLE imported_products (
  product_id INT PRIMARY KEY,
  name       VARCHAR(80) NOT NULL,
  price      DECIMAL(8,2) CHECK (price > 0),
  sku        VARCHAR(20) UNIQUE
);

-- Simulate batch processing with recovery from errors
BEGIN;

-- Record 1: valid
SAVEPOINT before_record_1;
INSERT INTO imported_products VALUES (1, 'Laptop', 999.99, 'LAP001');
SAVEPOINT after_record_1;

-- Record 2: valid
SAVEPOINT before_record_2;
INSERT INTO imported_products VALUES (2, 'Mouse', 19.99, 'MSE001');
SAVEPOINT after_record_2;

-- Record 3: would fail (negative price) — rollback just this record
SAVEPOINT before_record_3;
-- INSERT INTO imported_products VALUES (3, 'Bad Item', -10, 'BAD001'); -- would fail
-- ROLLBACK TO SAVEPOINT before_record_3;  -- skip this record

-- Record 4: valid
SAVEPOINT before_record_4;
INSERT INTO imported_products VALUES (4, 'Keyboard', 59.99, 'KBD001');
SAVEPOINT after_record_4;

COMMIT;

-- Result: 3 valid products, bad record skipped
SELECT * FROM imported_products ORDER BY product_id;

CREATE TABLE tasks (
  task_id  INT PRIMARY KEY,
  title    VARCHAR(100),
  status   VARCHAR(20) DEFAULT 'pending'
);

INSERT INTO tasks VALUES (1,'Task A','pending'),(2,'Task B','pending'),(3,'Task C','pending');

BEGIN;

-- Complete Task A
UPDATE tasks SET status = 'done' WHERE task_id = 1;
SAVEPOINT task_a_done;

-- Complete Task B
UPDATE tasks SET status = 'done' WHERE task_id = 2;
SAVEPOINT task_b_done;

-- Release task_a_done (no longer need to rollback to it)
RELEASE SAVEPOINT task_a_done;
-- Note: task A's UPDATE is NOT rolled back — RELEASE only removes the marker

-- Complete Task C
UPDATE tasks SET status = 'done' WHERE task_id = 3;

COMMIT;

SELECT * FROM tasks ORDER BY task_id;
